import{_ as e,c as l,o as s,ae as t}from"./chunks/framework.DTLW3OlO.js";const u=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"document/mysql.md","filePath":"document/mysql.md"}'),i={name:"document/mysql.md"};function n(r,a,o,c,h,m){return s(),l("div",null,a[0]||(a[0]=[t(`<h2 id="_1-启动mysql服务器" tabindex="-1">1.启动MYSQL服务器 <a class="header-anchor" href="#_1-启动mysql服务器" aria-label="Permalink to &quot;1.启动MYSQL服务器&quot;">​</a></h2><ul><li>使用 winmysqladmin</li><li>DOS方式下运行 d:/mysql/bin/mysqld （具体路径为mysql安装路径）</li><li>winpty mysql -uroot -p</li></ul><h2 id="_2-进入mysql交互操作界面" tabindex="-1">2.进入mysql交互操作界面 <a class="header-anchor" href="#_2-进入mysql交互操作界面" aria-label="Permalink to &quot;2.进入mysql交互操作界面&quot;">​</a></h2><ul><li>在DOS方式下，(在mysql安装目录下，如 C:\\Program Files\\MySQL\\MySQL Server 5.5\\bin) 运行语句： mysql -u root -p 输入密码即可</li></ul><h2 id="_3-退出mysql操作界面" tabindex="-1">3.退出MYSQL操作界面 <a class="header-anchor" href="#_3-退出mysql操作界面" aria-label="Permalink to &quot;3.退出MYSQL操作界面&quot;">​</a></h2><ul><li>quit 在mysql&gt;quit提示符下，输入quit可以随时退出交互操作界面</li></ul><h2 id="_4-第一条mysql命令" tabindex="-1">4.第一条MYSQL命令 <a class="header-anchor" href="#_4-第一条mysql命令" aria-label="Permalink to &quot;4.第一条MYSQL命令&quot;">​</a></h2><ul><li>mysql&gt;select version(),current_date(); 此命令要求mysql服务器输出它的版本号和当前日期</li><li>练习其它指令：select (20+5)*4; select (20+5)*4,sin(pi()/3); --- 如果结尾不加分号，则mysql视为你还会继续输入指令 <img src="http://hanhuankang.com/images/mysql/mysql01.png" alt="Image text"></li></ul><h2 id="_5-多行语句" tabindex="-1">5.多行语句 <a class="header-anchor" href="#_5-多行语句" aria-label="Permalink to &quot;5.多行语句&quot;">​</a></h2><ul><li>一条语句可以分成多行输入，直到出现分号“;”为止</li><li>mysql的关键字是不区分大小写的，如：select、from、where、group by、order by、having、update delete、insert into、sum、avg、min、max等等；查询内容是区分大小写的，如表名、字段名、内容等</li></ul><h2 id="_6-查看当前所有数据库" tabindex="-1">6.查看当前所有数据库 <a class="header-anchor" href="#_6-查看当前所有数据库" aria-label="Permalink to &quot;6.查看当前所有数据库&quot;">​</a></h2><ul><li>使用show语句找出服务上当前存在什么数据库： mysql&gt;show databases;</li></ul><h2 id="_7-创建一个数据库" tabindex="-1">7.创建一个数据库 <a class="header-anchor" href="#_7-创建一个数据库" aria-label="Permalink to &quot;7.创建一个数据库&quot;">​</a></h2><ul><li>mysql&gt;create databse hhk01; --- 创建一个名为 hhk01 的数据库，注意不同操作系统对大小写的敏感</li></ul><h2 id="_8-选择创建好的数据库" tabindex="-1">8.选择创建好的数据库 <a class="header-anchor" href="#_8-选择创建好的数据库" aria-label="Permalink to &quot;8.选择创建好的数据库&quot;">​</a></h2><ul><li>mysql&gt;use hhk01 --- 此时进入你所创建好的数据库hhk01,注意，不需要加分号</li></ul><h2 id="_9-创建一个数据库表" tabindex="-1">9.创建一个数据库表 <a class="header-anchor" href="#_9-创建一个数据库表" aria-label="Permalink to &quot;9.创建一个数据库表&quot;">​</a></h2><ul><li>首先看现在数据库中存在什么表： mysql&gt;show tables;</li><li>创建一个员工的生日表：mysql&gt;create table mytable (name varchar(20),sex char(1)),birth date,birthaddress varchar(20));</li></ul><h2 id="_10-显示表的结构" tabindex="-1">10.显示表的结构 <a class="header-anchor" href="#_10-显示表的结构" aria-label="Permalink to &quot;10.显示表的结构&quot;">​</a></h2><ul><li>mysql&gt;describe mytable;</li></ul><h2 id="_11-查询所有数据" tabindex="-1">11.查询所有数据 <a class="header-anchor" href="#_11-查询所有数据" aria-label="Permalink to &quot;11.查询所有数据&quot;">​</a></h2><ul><li>mysql&gt;select * from mytable;</li></ul><h2 id="_12-增加记录" tabindex="-1">12.增加记录 <a class="header-anchor" href="#_12-增加记录" aria-label="Permalink to &quot;12.增加记录&quot;">​</a></h2><ul><li>mysql&gt;insert into test3 values(&#39;abs&#39;); <img src="http://hanhuankang.com/images/mysql/mysql02.png" alt="Image text"></li></ul><h2 id="_13-选择特定行" tabindex="-1">13.选择特定行 <a class="header-anchor" href="#_13-选择特定行" aria-label="Permalink to &quot;13.选择特定行&quot;">​</a></h2><ul><li>mysql&gt;select * from mytable where name = &#39;tom&#39;;</li><li>where的参数指定了检索条件，还可以用组合条件来进行查询：</li><li>mysql&gt; select * from mytable where sex = &quot;f&quot; and birthaddress = &quot;china&quot;; <img src="http://hanhuankang.com/images/mysql/mysql03.png" alt="Image text"></li></ul><h2 id="_14-多表操作" tabindex="-1">14.多表操作 <a class="header-anchor" href="#_14-多表操作" aria-label="Permalink to &quot;14.多表操作&quot;">​</a></h2><ul><li>创建好两个表格 create table selfinfo (name varchar(20),sex char(1),birth DATE,address varchar(20)); create table scoreinfo (name varchar(20),score char(20));</li><li>查询单个表格信息：mysql&gt;select * from selfinfo; mysql&gt;select name,sex from selfinfo where name=&#39;tom&#39;;</li><li>查询多个表 mysql&gt;select name,score,sex,brith,address from selfinfo,scoreinfo where name=student and name=&#39;tom&#39;; --- where name=student表示两个表的这两个字段值相等 <img src="http://hanhuankang.com/images/mysql/mysql04.png" alt="Image text"></li></ul><h2 id="_15-增加一列" tabindex="-1">15.增加一列 <a class="header-anchor" href="#_15-增加一列" aria-label="Permalink to &quot;15.增加一列&quot;">​</a></h2><h2 id="在table表中增加一列-mysql-alter-table-scoreinfo-add-column-level-char-1" tabindex="-1">在table表中增加一列：mysql&gt;alter table scoreinfo add column level char(1); <a class="header-anchor" href="#在table表中增加一列-mysql-alter-table-scoreinfo-add-column-level-char-1" aria-label="Permalink to &quot;在table表中增加一列：mysql&gt;alter table scoreinfo add column level char(1);&quot;">​</a></h2><p><img src="http://hanhuankang.com/images/mysql/mysql05.png" alt="Image text"></p><h2 id="_16-修改记录" tabindex="-1">16.修改记录 <a class="header-anchor" href="#_16-修改记录" aria-label="Permalink to &quot;16.修改记录&quot;">​</a></h2><ul><li>mysql&gt;update mytable set birth = &quot;1973-09-02&quot; where name = &quot;tom&quot;;</li></ul><h2 id="_17-增加记录" tabindex="-1">17.增加记录 <a class="header-anchor" href="#_17-增加记录" aria-label="Permalink to &quot;17.增加记录&quot;">​</a></h2><h2 id="_18-删除记录" tabindex="-1">18.删除记录 <a class="header-anchor" href="#_18-删除记录" aria-label="Permalink to &quot;18.删除记录&quot;">​</a></h2><ul><li>删除表中的一条记录： mysql&gt;delete from scoreinfo where name=&#39;hanke&#39;; <img src="http://hanhuankang.com/images/mysql/mysql06.png" alt="Image text"></li></ul><h2 id="_19-删除表" tabindex="-1">19.删除表 <a class="header-anchor" href="#_19-删除表" aria-label="Permalink to &quot;19.删除表&quot;">​</a></h2><ul><li>删除一个或多个表：mysql&gt;drop table scoreinfo,selfinfo; <img src="http://hanhuankang.com/images/mysql/mysql07.png" alt="Image text"></li></ul><h2 id="_20-数据库的删除" tabindex="-1">20.数据库的删除 <a class="header-anchor" href="#_20-数据库的删除" aria-label="Permalink to &quot;20.数据库的删除&quot;">​</a></h2><ul><li>查看所有数据库： mysql&gt;show databases;</li><li>删除数据库：mysql&gt;drop database test,hhk01; <img src="http://hanhuankang.com/images/mysql/mysql08.png" alt="Image text"></li></ul><h2 id="_21-数据库的备份" tabindex="-1">21.数据库的备份 <a class="header-anchor" href="#_21-数据库的备份" aria-label="Permalink to &quot;21.数据库的备份&quot;">​</a></h2><ul><li>退回到DOS：mysql&gt;quit</li><li>使用命令对数据库hhk02进行备份：mysql&gt;mysqldump -u root -pxxx hhk02&gt;hhk02.sql</li><li>使用命令对数据库hhk02进行还原，先创建一个空数据库hhk03：mysql&gt;mysql -u root -pxxx hhk03&lt;hhk02.sql</li><li>hhk02.sql就是数据库hhk02的备份文件 <img src="http://hanhuankang.com/images/mysql/mysql09.png" alt="Image text"><img src="http://hanhuankang.com/images/mysql/mysql10.png" alt="Image text"></li></ul><h2 id="_22-用批处理方式使用mysql" tabindex="-1">22.用批处理方式使用MySQL <a class="header-anchor" href="#_22-用批处理方式使用mysql" aria-label="Permalink to &quot;22.用批处理方式使用MySQL&quot;">​</a></h2><h2 id="_23-先用root登录到mysql" tabindex="-1">23.先用root登录到mysql <a class="header-anchor" href="#_23-先用root登录到mysql" aria-label="Permalink to &quot;23.先用root登录到mysql&quot;">​</a></h2><h2 id="_24-创建一个用户" tabindex="-1">24.创建一个用户 <a class="header-anchor" href="#_24-创建一个用户" aria-label="Permalink to &quot;24.创建一个用户&quot;">​</a></h2><p><img src="http://hanhuankang.com/images/mysql/mysql20.png" alt="Image text"></p><h2 id="mysql学习笔记02" tabindex="-1">Mysql学习笔记02 <a class="header-anchor" href="#mysql学习笔记02" aria-label="Permalink to &quot;Mysql学习笔记02&quot;">​</a></h2><ul><li>mysql表中添加一列：alter table strategy_factor add column tzhname1 varchar(255); <ul><li>alter table strategy_factor add tzhname2 varchar(255) character set utf8 collate utf8_bin not null default &#39;&#39;, add szhname2 varchar(255) character set utf8 collate utf8_bin not null default &#39;&#39;;</li></ul></li><li>mysql表中删除一列：alter table strategy_factor drop column tzhname1;</li><li>mysql表中修改列类型：alter table test modify address char(10); 或者：alter table test change address address char(40);</li><li>mysql表中修改列名：alter table test change column address address1 varchar(30);</li><li>mysql修改表名：alter table test rename test1; <ul><li>alter table strategy_factor change column tzhname2 tzhname varchar(255) character set utf8 collate utf8_bin not null default &#39;&#39; comment &#39;项目中文名称&#39;,change column szhname2 szhname varchar(255) character set utf8 collate utf8_bin not null default &#39;&#39; comment &#39;广告位中文名称&#39;;</li></ul></li><li>mysql更新表内容：update tablename set name = &#39;hhk&#39;, score = 95 where id = 1;</li><li>mysql表中插入一行：INSERT INTO table_name (列1,列2...) VALUES (值1,值2...) <ul><li>INSERT INTO movie_film_word (film_id,word,type) VALUES (436985, &#39;haha3&#39;, 0);</li></ul></li><li>mysql查询某个表的数据条数：select count(*) from movie_film_word;</li></ul><h2 id="mysql语句中的其他应用" tabindex="-1">Mysql语句中的其他应用 <a class="header-anchor" href="#mysql语句中的其他应用" aria-label="Permalink to &quot;Mysql语句中的其他应用&quot;">​</a></h2><ul><li>concat()函数：将多个字符串连接成一个字符串，返回连接后的字符串<div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>  select concat(id, name, score) as info from tt2;</span></span>
<span class="line"><span>  //输出 1小明0</span></span>
<span class="line"><span>  //添加分隔符</span></span>
<span class="line"><span>  select concat(id, &#39;.&#39;, name, &#39;.&#39;, score) as info from tt2;</span></span></code></pre></div></li><li>concat_ws()函数：将多个字符串连接成一个字符串，但可以一次性指定分隔符(concat_ws就是 concat with separator) <ul><li>语法： concat_ws(separator, str1,str2, ...) 第一个参数为指定分隔符，分隔符不能为null，否则返回结果为null</li></ul><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>  select concat_ws(&#39;,&#39;, id, name, score) as info from tt2;</span></span></code></pre></div></li><li>group by: 分组函数 <ul><li>聚合函数： sum 求和、max 最大值、min 最小值、avg 平均值、 first 第一条记录、 last 最后一条记录、 count 统计记录数</li><li></li></ul><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>  //取平均数</span></span>
<span class="line"><span>    select category, avg(num) as average from A group by category;</span></span>
<span class="line"><span>  //group by all 按多列分组（只有两个列的内容都相同的，才会求和）</span></span>
<span class="line"><span>    select category, summary, sum(num) as total from A group by all category, summary;</span></span></code></pre></div><ul><li>在有 group by 的语句中，select指定的字段要么就包含在group by 语句的后面，作为分组的依据，要么就包含在聚合函数中</li></ul></li><li>group_concat()函数：（将group by 产生的同一个分组中的值链接起来，返回一个字符串结果） <ul><li>语法： group_concat(distinct[] 要链接的字段 [order by 排序字段 asc/desc] [separator &#39;分隔符&#39;]) -- 通过使用 distinct 可以排除重复值；如果希望排序，可以使用 order by 语句，separator 是一个字符串值，缺省为一个逗号</li></ul><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>  select name, group_concat(id) from tt2 group by name;  //将name相同的元素，输出其name和id，id采用逗号分隔</span></span>
<span class="line"><span>  select name group_concat(id order by id desc separator &#39;_&#39;) from tt2 group by name; // 将name相同的元素全部合并输出，所有id从大到小排序，且用&#39;_&#39;分隔</span></span>
<span class="line"><span>  select name group_concat(concat_ws(&#39;-&#39;, id, score) order by id separator &#39;|&#39;) from tt2 group by name; // 将name相同的元素全部合并输出，其id、score用 &#39;_&#39;分隔</span></span></code></pre></div></li><li>filed()函数：自定义排序顺序，结合 order by 可以将查询结果集按照参数顺序表返回<div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>  select * from books where &#39;books&#39;.&#39;author&#39; in (&#39;李雷&#39;, &#39;韩梅梅&#39;, &#39;安华&#39;) order by filed(author, &#39;李雷&#39;, &#39;韩梅梅&#39;);</span></span></code></pre></div></li><li>like 运算符：(用于where表达式中，以搜索匹配字段中的指定内容) <ul><li>语法：where column like pattern<div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>  select * from users where username like &#39;小%&#39;; // 将用户名形如“小明”、“小王”等的数据找出来</span></span></code></pre></div></li><li>mysql like 语句通常是不区分大小写的，可以使用 binary 来区分大小写<div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>  select * from users where username like binary &#39;%Azz%&#39;;</span></span></code></pre></div></li><li>当like 加上binary操作符之后，会严格区分英文大小写，因此检索内容如果出现中英文混合且需要忽略英文大小写时，可以使用mysql的upper()和concat()函数 <ul><li>upper() 将英文字符转为大写，同ucase()</li><li>concat() 将多个字符串连接成一个字符串</li></ul><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>  select * from users where upper(username) like binary concat(&#39;%&#39;,upper(&#39;a中文b&#39;),&#39;%&#39;);</span></span></code></pre></div></li><li>like运算符要对字段数据进行逐一扫描匹配，实际执行的效率比较差</li></ul></li><li>SQL_CALC_FOUND_ROWS <ul><li>在处理分页程序的时候，会使用limit来限制返回的数量，然后有两种获取分页的方法 <ul><li>方法一：在select 语句中加入 SQL_CALC_FOUND_ROWS选项，然后通过 SELECT FOUND_ROWS();来获取总行数：<div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>  select sql_calc_found_rows * from table where id &gt; 100 limit 10;</span></span>
<span class="line"><span>  select found_rows();</span></span></code></pre></div></li><li>方法二：使用正常SQL语句，然后再用 SELECT COUNT(*)来获取总行数：<div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>  select * from table where id &gt; 100 limit 10;</span></span>
<span class="line"><span>  select count(*) from table where id &gt; 100;</span></span></code></pre></div></li></ul></li><li>一般来说 sql_calc_found_rows 是比较慢的，sql执行的时间甚至会达到10倍那么夸张</li></ul></li><li>联表删除 <ul><li>删除表 movie_film_tags 中 film_id 字段 与表 movie_film 中的 id 字段 相同，且 movie_film 中 ref_id 以 &quot;360kan&quot; 开头的数据<div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>  DELETE t1 FROM movie_film_tags t1 WHERE (select t2.ref_id from movie_film t2 where t2.id=t1.film_id) like &#39;360kan%&#39;</span></span></code></pre></div></li></ul></li><li></li></ul>`,50)]))}const p=e(i,[["render",n]]);export{u as __pageData,p as default};
